text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": {
      "confirmed_decisions": [
        {
          "topic": "공개 릴리스 목표 시점",
          "decision": "스모크 테스트가 통과하면 금요일 15:00 KST를 공개 릴리스 목표로 둔다.",
          "condition": "스모크 테스트 통과",
          "source_certainty": "확정"
        },
        {
          "topic": "packageName mismatch 대응",
          "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
          "source_certainty": "확정"
        }
      ],
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
          "disposition": "기각",
          "reason": "논의 후 채택되지 않았고, 우선 package config를 확인하는 방향으로 정리되었다.",
          "source_certainty": "확정"
        }
      ],
      "internal_stretch_goals": [
        {
          "goal": "수요일 릴리스",
          "status": "내부 스트레치 목표",
          "note": "최종 공개 릴리스 결정이 아니다.",
          "source_certainty": "확정"
        }
      ]
    },
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었지만, 담당자와 확정 마감은 정해지지 않았다.",
        "source_certainty": "명시됨"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "source_certainty": "확정"
      },
      {
        "risk": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자를 오도할 수 있다.",
        "source_certainty": "확정"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "source_certainty": "미해결"
      },
      {
        "question": "릴리스 노트에 수요일 내부 스트레치 목표를 언급해야 하는가?",
        "source_certainty": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정됨",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정됨",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일 가능 시",
      "status": "제안됨",
      "source_certainty": "제안 수준"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "선행 결과 대기",
      "source_certainty": "확정"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST까지 스모크 테스트 결과와 통과 여부를 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 확인 결과를 점검한다.",
      "금요일 12:00 KST까지 action_items.md의 실패 트리아지 노트 작성 여부를 확인한다.",
      "README 설치 단계 검토의 담당자 지정 필요 여부와 최신성 위험을 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 미해결 항목으로 유지한다."
    ],
    "do_not_invent": [
      "고객명이나 외부 파트너를 추가하지 않는다.",
      "예산 정보를 추가하지 않는다.",
      "보안 사고나 프로덕션 장애를 있었던 일처럼 적지 않는다.",
      "법무 승인 요구사항을 있었다고 적지 않는다.",
      "정해지지 않은 담당자나 마감을 임의로 확정하지 않는다."
    ]
  },
  "non_invention_rules": {
    "scope": "인라인 공개 안전 합성 픽스처에 있는 정보만 사용한다.",
    "forbidden_fact_types": [
      "고객 정보",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자",
      "미지정 마감",
      "골든 또는 레퍼런스 출력 추정"
    ],
    "missing_fact_handling": [
      "담당자가 없으면 null로 남긴다.",
      "정확한 마감이 없으면 null로 남긴다.",
      "제안, 내부 스트레치 목표, 위험, 열린 질문을 확정 결정으로 승격하지 않는다."
    ]
  }
}
